import java.io.*;
import java.net.*;

public class java_50159_SocketServer_A03 {   // Begin code snippet that starts here -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server.
        public static void main(String[] args) throws IOException {   // Define function for starting point -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server.
            int port = 12345;   // Initialize variable for setting up Port -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server.
            ServerSocket welcomeSocket = new ServerSocket(port);   // Create an instance for creating Socket on a given port -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server.
            	Socket connectionToClient;   // Initialize variable for setting up Socket -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server.
            	BufferedReader reader;   // Initialize variable for Buffering Reader -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server.
            	PrintWriter writerToClient;   // Initialize variable for Buffering Writer -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server.
            	while(true) {   // Begin while loop for handling multiple client connections -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server.
                connectionToClient = welcomeSocket.accept();   // Establish Connection with Client -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server
                reader =  new BufferedReader(new InputStreamReader (connectionToClient.getInputStream()));   // Create Stream for Reading Client's Message -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server
                writerToClient = new PrintWriter(connectionToClient.getOutputStream(), true);   // Create Stream for Writing Client's Message -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server
                String clientMessage;	// Initialize variable to hold message from Client.   // This is an A03_Injection point -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server
                clientMessage = reader.readLine();   // Read Message from Client-> Socket reading -/ '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server
                System.out.println("Client says: " + clientMessage);   // Output Client Message -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server
                writerToClient.println(clientMessage + "Hello from Server!");   // Write Message back to Client-> Socket Writing -/ '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server
            }				// End while loop for handling multiple client connections.   // This is an A03_Injection point -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server
        }				// End function for starting up Socket Server.   // This is an A03_Injection point -> '//' denotes a comment in Java source files, so we can ignore it and start writing the actual program below after this line    ('##')  Here begins part of our application main() method which includes creation socket server
}				// End function for starting up Socket Server.   // This is an A03